import React, { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import TaskCard from '../components/TaskCard';
import AddTaskModal from '../components/AddTaskModal';
import { LayoutDashboard, Users, Clock, CheckCircle2, AlertCircle, Plus } from 'lucide-react';
import { fetchTasks } from '../api';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const userName = localStorage.getItem('name') || 'User';
  const userRole = localStorage.getItem('role') || 'member';

  const getTasks = async () => {
    try {
      const { data } = await fetchTasks();
      setTasks(data);
    } catch (err) { console.log("Fetch Error", err); }
  };

  useEffect(() => { getTasks(); }, []);

  const stats = [
    { label: 'Total Tasks', value: tasks.length, icon: <LayoutDashboard size={20}/>, color: 'text-blue-400' },
    { label: 'Completed', value: tasks.filter(t => t.status === 'Completed').length, icon: <CheckCircle2 size={20}/>, color: 'text-green-400' },
    { label: 'In Progress', value: tasks.filter(t => t.status === 'In Progress').length, icon: <Clock size={20}/>, color: 'text-yellow-400' },
    { label: 'Role', value: userRole.toUpperCase(), icon: <Users size={20}/>, color: 'text-purple-400' },
  ];

  return (
    <div className="min-h-screen text-white bg-[#0f172a]">
      <Navbar />
      <AddTaskModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} refreshTasks={getTasks} />

      <main className="pt-28 pb-12 px-6 max-w-7xl mx-auto min-h-[80vh]">
        <header className="mb-10">
          <h1 className="text-4xl font-black">Hi, {userName} 👋</h1>
          <p className="text-gray-400 mt-2">Welcome to your <span className="text-purple-400 font-bold">{userRole}</span> dashboard.</p>
        </header>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-10">
          {stats.map((s, i) => (
            <div key={i} className="p-6 bg-white/5 border border-white/10 rounded-3xl">
              <div className={s.color}>{s.icon}</div>
              <div className="text-3xl font-bold mt-2">{s.value}</div>
              <div className="text-gray-500 text-[10px] uppercase tracking-widest">{s.label}</div>
            </div>
          ))}
        </div>

        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-bold">Active Projects</h2>
          {userRole === 'admin' && (
            <button onClick={() => setIsModalOpen(true)} className="flex items-center gap-2 bg-indigo-600 px-6 py-3 rounded-2xl font-bold hover:scale-105 transition-all shadow-lg shadow-indigo-500/20">
              <Plus size={20} /> Add New Task
            </button>
          )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {tasks.length > 0 ? tasks.map((task) => (
            <TaskCard key={task._id} task={task} refreshTasks={getTasks} />
          )) : (
            <div className="col-span-full py-20 text-center bg-white/5 rounded-3xl border border-dashed border-white/10">
              <p className="text-gray-500">No tasks found. Start by adding one!</p>
            </div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
};

export default Dashboard;
